code = """import json
import pandas as pd

# Get the data from storage
lite_fiction_books_path = locals()['var_functions.query_db:8']
perfect_rating_books = locals()['var_functions.query_db:6']

# Load the books data from file if it's a path
if isinstance(lite_fiction_books_path, str):
    with open(lite_fiction_books_path, 'r') as f:
        lite_fiction_books = json.load(f)
else:
    lite_fiction_books = lite_fiction_books_path

# Convert to DataFrames
df_books = pd.DataFrame(lite_fiction_books)
df_ratings = pd.DataFrame(perfect_rating_books)

# Extract numeric ID from purchase_id and book_id for matching
df_books['id_num'] = df_books['book_id'].str.extract('bookid_(\\d+)').astype(int)
df_ratings['id_num'] = df_ratings['purchase_id'].str.extract('purchaseid_(\\d+)').astype(int)

# Merge the dataframes on the numeric ID
merged_df = pd.merge(df_books, df_ratings, on='id_num', how='inner')

print(f"Found {len(merged_df)} matching books after merge")
print(f"Sample merged data: {merged_df[['title', 'book_id', 'avg_rating', 'review_count']].head() if len(merged_df) > 0 else 'No matches'}")

# Filter for English-language books
english_books = []
for idx, row in merged_df.iterrows():
    details = str(row.get('details', '')).lower()
    categories = str(row.get('categories', '')).lower()
    
    # Check if the book is in English
    if 'english' in details or 'english' in categories:
        english_books.append({
            'title': row['title'],
            'book_id': row['book_id'],
            'avg_rating': row['avg_rating'],
            'review_count': row['review_count'],
            'categories': row['categories']
        })

print(f"Found {len(english_books)} English books with perfect ratings")

# Return the results
result = json.dumps(english_books, indent=2, ensure_ascii=False)
print('__RESULT__:')
print(result)"""

